import React, { Fragment, useContext } from 'react';
import { grayOne, grayThree, greenOne } from './Color';
import { AppContext } from '../../App';
import { AllCodingIcon } from '../fetchdata/Projects';

const SkillMain = (props) => {

    const { data } = useContext(AppContext)

    return (
        <Fragment>
	    	<div>
	    		<div className={`${data.darkMode ? grayOne : grayThree} col-span-1`}>
	    			<div className="my-4 flex items-center justify-between">
	    				<span className={`${greenOne} w-1/2`}>Programming Language:&nbsp;</span>
	    				<span className="w-1/2">Python, Javascript</span>
	    			</div>
	    			<div className="my-4 flex items-center justify-between">
	    				<span className={`${greenOne} w-1/2`}>Frontend:&nbsp;</span>
	    				<span className="w-1/2">HTML5, CSS3, Sass, Bootstrap, Tailwind Css, Material css, Reactjs, Vuejs</span>
	    			</div>
	    			<div className="my-4 flex items-center justify-between">
	    				<span className={`${greenOne} w-1/2`}>Backend:&nbsp;</span>
	    				<span className="w-1/2">Nodejs, Expressjs, Django</span>
	    			</div>
	    			<div className="my-4 flex items-center justify-between">
	    				<span className={`${greenOne} w-1/2`}>Api:&nbsp;</span>
	    				<span className="w-1/2">Django REST Framework, Nodejs</span>
	    			</div>
	    			<div className="my-4 flex items-center justify-between">
	    				<span className={`${greenOne} w-1/2`}>Concepts:&nbsp;</span>
	    				<span className="w-1/2">RESTful Principles, Agile Methodologies, Databese Query</span>
	    			</div>
	    			<div className="my-4 flex items-center justify-between">
	    				<span className={`${greenOne} w-1/2`}>Tools:&nbsp;</span>
	    				<span className="w-1/2">Docker, Git, Vim, Github, Bitbucket</span>
	    			</div>
	    		</div>
	    	</div>
    		<div className="flex flex-wrap items-center justify-center mt-6">
    			{
    				AllCodingIcon.map((item)=> {
    					return (
    						<img className="mx-2" src={item} alt="icon" />
    					)
    				})
    			}
    		</div>
	    </Fragment>
    )
}

export default SkillMain;